const defaultParams = {
  PRIMER_TASK: 'generic',
  PRIMER_PICK_LEFT_PRIMER: 1,
  PRIMER_PICK_INTERNAL_OLIGO: 0,
  PRIMER_PICK_RIGHT_PRIMER: 1,
  PRIMER_OPT_SIZE: 20,
  PRIMER_MIN_SIZE: 18,
  PRIMER_MAX_SIZE: 22,
  PRIMER_PRODUCT_SIZE_RANGE: '35-45',
  PRIMER_EXPLAIN_FLAG: 1,
  PRIMER_MAX_NS_ACCEPTED: 0,
  PRIMER_NUM_RETURN: 5,
  PRIMER_MAX_POLY_X: 4,
  PRIMER_GC_CLAMP: 1,
  PRIMER_MAX_END_STABILITY: 9.0
}

const labels: Record<string, string> = {
  PRIMER_TASK: 'Primer Task',
  PRIMER_PICK_LEFT_PRIMER: 'Pick Left Primer',
  PRIMER_PICK_INTERNAL_OLIGO: 'Pick Internal Oligo',
  PRIMER_PICK_RIGHT_PRIMER: 'Pick Right Primer',
  PRIMER_OPT_SIZE: 'Optimal Primer Size',
  PRIMER_MIN_SIZE: 'Minimum Primer Size',
  PRIMER_MAX_SIZE: 'Maximum Primer Size',
  PRIMER_PRODUCT_SIZE_RANGE: 'Product Size Range (e.g. 35-45)',
  PRIMER_EXPLAIN_FLAG: 'Explain Flag',
  PRIMER_MAX_NS_ACCEPTED: 'Max Ns Accepted',
  PRIMER_NUM_RETURN: 'Number of Primer Pairs Returned',
  PRIMER_MAX_POLY_X: 'Max Poly-X (e.g., AAAA)',
  PRIMER_GC_CLAMP: 'GC Clamp (GC at 3" end)',
  PRIMER_MAX_END_STABILITY: 'Max End Stability'
}

const tooltips: Record<string, string> = {
  PRIMER_TASK: 'Defines the task to perform: generic, pick_pcr_primers, check_primers, etc.',
  PRIMER_PICK_LEFT_PRIMER: 'If 1, Primer3 will attempt to pick left primers.',
  PRIMER_PICK_INTERNAL_OLIGO: 'If 1, Primer3 will attempt to pick internal oligos (probes).',
  PRIMER_PICK_RIGHT_PRIMER: 'If 1, Primer3 will attempt to pick right primers.',
  PRIMER_OPT_SIZE: 'The ideal primer length.',
  PRIMER_MIN_SIZE: 'The minimum allowed primer length.',
  PRIMER_MAX_SIZE: 'The maximum allowed primer length.',
  PRIMER_PRODUCT_SIZE_RANGE: 'Desired PCR product size(s), e.g. 35-45 or 100-150 200-250 (first has priority).',
  PRIMER_EXPLAIN_FLAG: 'Set to 1 to receive detailed output about primer picking decisions.',
  PRIMER_MAX_NS_ACCEPTED: 'Maximum number of ambiguous bases (N) allowed in the sequence.',
  PRIMER_NUM_RETURN: 'Maximum number of primer pairs to return.',
  PRIMER_MAX_POLY_X: 'Max length of a single-base repeat (e.g. AAAA).',
  PRIMER_GC_CLAMP: 'Number of G/C bases required at the 3" end of primers.',
  PRIMER_MAX_END_STABILITY: 'Maximum allowed 3" end stability (kcal/mol).'
}

const ASODesign = () => {
  const [fastaInput, setFastaInput] = useState('')
  const [params, setParams] = useState({ ...defaultParams })
  const [expanded, setExpanded] = useState<string | false>(false)
  const [loading, setLoading] = useState(false)
  const [resultData, setResultData] = useState<any | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [maxHeight, setMaxHeight] = useState(window.innerHeight - 400)

  const { selectedRegions } = useAppSelecter(
    (state) => ({
      selectedRegions: state.rbSettings.selectedRegions
    }),
    shallowEqualApp
  )

  const handleChange = (key: string) => (e: ChangeEvent<HTMLInputElement>) => {
    setParams((prev) => ({ ...prev, [key]: e.target.value }))
  }

  const validateFastaWithReason = (input: string): { valid: boolean; error?: string } => {
    const lines = input.trim().split('\n')
    if (lines.length === 0) {
      return { valid: false, error: 'Input is empty.' }
    }

    let lineNumber = 0
    let inRecord = false
    let hasSeq = false
    const baseRegex = /^[ACGTURYKMSWBDHVN-]+$/i

    for (const line of lines) {
      lineNumber++
      const trimmed = line.trim()

      if (trimmed.startsWith('>')) {
        if (inRecord && !hasSeq) {
          return { valid: false, error: `Missing sequence for header at line ${lineNumber - 1}.` }
        }
        inRecord = true
        hasSeq = false
      } else if (inRecord) {
        if (!baseRegex.test(trimmed)) {
          return {
            valid: false,
            error: `Invalid character(s) in sequence at line ${lineNumber}: "${trimmed}"`
          }
        }
        hasSeq = true
      } else {
        return { valid: false, error: `Line ${lineNumber} must start with '>' for FASTA header.` }
      }
    }

    if (inRecord && !hasSeq) {
      return { valid: false, error: `Final record is missing sequence after header.` }
    }

    return { valid: true }
  }

  const handleDesignClick = async () => {
    const { valid, error: formatError } = validateFastaWithReason(fastaInput)
    if (!valid) {
      setError(`FASTA format error: ${formatError}`)
      setLoading(false)
      return
    }

    setLoading(true)
    setResultData(null)

    const payload = {
      fasta: fastaInput,
      config: params
    }

    try {
      const res = await fetch('https://api.rbrowser.org/api/v1/aso_design/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      })

      if (!res.ok) throw new Error(`HTTP ${res.status}`)
      const data = await res.json()
      setResultData(data)
    } catch (err) {
      setError((err as Error).message || 'Unknown error')
    } finally {
      setLoading(false)
    }
  }

  const handleReset = () => {
    setParams({ ...defaultParams })
    setFastaInput('')
    setResultData(null)
    setExpanded(false)
  }

  // 粘贴板复制工具
  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text)
  }

  const renderInformation = (info: Record<string, any>) => {
    return Object.entries(info).map(([key, value]) => (
      <Typography key={key} fontSize='sm' mb={0.5}>
        <strong>{key}:</strong>{' '}
        {Array.isArray(value) || typeof value === 'object' ? JSON.stringify(value, null, 2) : String(value)}
      </Typography>
    ))
  }

  const validateInput = (key: string, value: string): boolean => {
    if (key === 'PRIMER_PRODUCT_SIZE_RANGE') return /^\d+-\d+(\s+\d+-\d+)*$/.test(value)
    if (/SIZE/.test(key) || /NUM_RETURN|GC_CLAMP/.test(key)) return /^\d+$/.test(value)
    if (/FLAG|PRIMER_PICK/.test(key)) return /^(0|1)$/.test(value)
    if (key === 'PRIMER_MAX_END_STABILITY') return /^\d+(\.\d+)?$/.test(value)
    return true
  }

  const groupedKeys = {
    General: ['PRIMER_TASK', 'PRIMER_EXPLAIN_FLAG'],
    'Primer Picking': ['PRIMER_PICK_LEFT_PRIMER', 'PRIMER_PICK_INTERNAL_OLIGO', 'PRIMER_PICK_RIGHT_PRIMER'],
    'Primer Size & Product': ['PRIMER_OPT_SIZE', 'PRIMER_MIN_SIZE', 'PRIMER_MAX_SIZE', 'PRIMER_PRODUCT_SIZE_RANGE'],
    Filters: [
      'PRIMER_MAX_NS_ACCEPTED',
      'PRIMER_NUM_RETURN',
      'PRIMER_MAX_POLY_X',
      'PRIMER_GC_CLAMP',
      'PRIMER_MAX_END_STABILITY'
    ]
  }

  useEffect(() => {
    // check if currentRNA is set in localStorage
    onStorageChange('currentRNA', (newValue, oldValue) => {
      console.log('currentRNA changed from', oldValue, 'to', newValue)
      if (!newValue) return

      getBrowserRegion({
        transcriptome: 'hg38',
        search: newValue,
        by: 'auto',
        offset: 0
      }).then((res) => {
        if (res.status === 200) {
          console.log('getBrowserRegion res', res)
          const { region } = res.data.results
          const { chrom, start, end, strand, trans_id, trans_name } = region[0]

          const fasta_name = `${trans_name}|${trans_id}|${chrom}|${start}|${end}|${strand}`

          getTranscriptSequence({
            transcriptome: 'hg38',
            search: newValue,
            by: 'auto',
            offset: 0
          })
            .then((seqRes) => {
              if (seqRes.status === 200) {
                const sequence = seqRes.data.results.sequence.sequence
                setFastaInput(`>${fasta_name}\n${sequence}`)
              } else {
                console.error('Failed to fetch transcript sequence:', seqRes)
              }
            })
            .catch((err) => {
              console.error('Error fetching transcript sequence:', err)
            })
        }
      })
    })

    onStorageChange('setSelectedRegions', (newValue, oldValue) => {
      console.log('setSelectedRegions changed from', oldValue, 'to', newValue)
      if (!newValue) return

      const extractGenomesWithStrand = (regionsObj: Record<string, any>) =>
        Object.values(regionsObj).map((item: any) => ({
          ...item.genome,
          strand: item.rna?.strand ?? ''
        }))

      let regionData: Record<string, any>
      try {
        regionData = typeof newValue === 'string' ? JSON.parse(newValue) : newValue
      } catch (err) {
        console.error('Failed to parse selectedRegions JSON:', err)
        return
      }

      const genomeList = extractGenomesWithStrand(regionData)
      console.log('genomeList:', genomeList)

      Promise.all(
        genomeList.map(async (region) => {
          const { chr, start, end, strand } = region
          try {
            const seqRes = await getTranscriptSequence({
              transcriptome: 'hg38',
              search: `${chr}:${start}-${end}:${strand}`,
              by: 'position',
              offset: 0
            })
            if (seqRes.status === 200) {
              const sequence = seqRes.data.results.sequence.sequence
              const fasta_name = `chr${chr}:${start}-${end}(${strand})`
              return `>${fasta_name}\n${sequence}`
            } else {
              console.error('Failed to fetch transcript sequence:', seqRes)
              return ''
            }
          } catch (err) {
            console.error('Error fetching transcript sequence:', err)
            return ''
          }
        })
      ).then((fastaArr) => {
        const fastaStr = fastaArr.filter(Boolean).join('\n')
        setFastaInput(fastaStr)
      })

      //  getTranscriptSequence({
      //   transcriptome: 'hg38',
      //   search: `${chrom}|${start}|${end}|${strand}`,
      //   by: 'position',
      //   offset: 0
      // })
      //   .then((seqRes) => {
      //     if (seqRes.status === 200) {
      //       const sequence = seqRes.data.results.sequence.sequence
      //       setFastaInput(`>${fasta_name}\n${sequence}`)
      //     } else {
      //       console.error('Failed to fetch transcript sequence:', seqRes)
      //     }
      //   })
      //   .catch((err) => {
      //     console.error('Error fetching transcript sequence:', err)
      //   })
      // getBrowserRegion({
      //   transcriptome: 'hg38',
      //   search: newValue,
      //   by: 'tname',
      //   offset: 0
      // }).then((res) => {
      //   if (res.status === 200) {
      //     console.log('getBrowserRegion res', res)
      //     const { region } = res.data.results
      //     const { chrom, start, end, strand, trans_id, trans_name } = region[0]

      //     const fasta_name = `${trans_name}|${trans_id}|${chrom}|${start}|${end}|${strand}`

      //   }
      // })
    })

    // onStorageChange('rnabrowser-selectedRegions', async (newValue, oldValue) => {
    //   console.log('rnabrowser-selectedRegions changed:', newValue)
    //   if (!newValue) return

    //   let regionData: Record<string, any>
    //   try {
    //     regionData = typeof newValue === 'string' ? JSON.parse(newValue) : newValue
    //   } catch (err) {
    //     console.error('Failed to parse selectedRegions JSON:', err)
    //     return
    //   }

    //   const regions = Object.values(regionData)
    //   const fastaParts: string[] = []

    //   for (const region of regions) {
    //     const {
    //       name,
    //       genome: { chr, start, end },
    //       rna: { strand }
    //     } = region as any

    //     try {
    //       const res = await getTranscriptSequence({
    //         transcriptome: 'hg38',
    //         search: `${chr}:${start}-${end}`,
    //         by: 'position',
    //         offset: 0
    //       })

    //       if (res.status === 200) {
    //         const sequence = res.data.results.sequence.sequence
    //         const fasta_name = `${name}|${chr}|${start}|${end}|${strand}`
    //         fastaParts.push(`>${fasta_name}\n${sequence}`)
    //       } else {
    //         console.error(`Failed to fetch sequence for ${name}:`, res)
    //       }
    //     } catch (err) {
    //       console.error(`Error fetching sequence for ${name}:`, err)
    //     }
    //   }

    //   if (fastaParts.length > 0) {
    //     setFastaInput(fastaParts.join('\n'))
    //     console.log('Fasta input set from selected regions:', fastaParts.join('\n'))
    //   }
    // })

    const handleResize = () => {
      setMaxHeight(window.innerHeight - 500)
    }
    window.addEventListener('resize', handleResize)
    return () => window.removeEventListener('resize', handleResize)
  }, [])

  useEffect(() => {
    console.log('selectedRegions useEffect', selectedRegions)
    // 初始化参数
    // getBrowserRegion({
    //   transcriptome: 'hg38',
    //   search: newValue,
    //   by: 'tname',
    //   offset: 0
    // }).then((res) => {
    //   if (res.status === 200) {
    //     console.log('getBrowserRegion res', res)
    //     const { region } = res.data.results
    //     const { chrom, start, end, strand, trans_id, trans_name } = region[0]

    //     const fasta_name = `${trans_name}|${trans_id}|${chrom}|${start}|${end}|${strand}`

    //     getTranscriptSequence({
    //       transcriptome: 'hg38',
    //       search: newValue,
    //       by: 'tname',
    //       offset: 0
    //     })
    //       .then((seqRes) => {
    //         if (seqRes.status === 200) {
    //           const sequence = seqRes.data.results.sequence.sequence
    //           setFastaInput(`>${fasta_name}\n${sequence}`)
    //         } else {
    //           console.error('Failed to fetch transcript sequence:', seqRes)
    //         }
    //       })
    //       .catch((err) => {
    //         console.error('Error fetching transcript sequence:', err)
    //       })
    //   }
    // })
  }, [selectedRegions])

  return (
    <>
      <PanelMenu to='/aso_design' name='ASO Design' did='aso_design' />
      <PanelBody>
        <Box sx={{ p: 3 }}>
          {/* 显示输入和设置部分，仅当不在 loading 且无结果时显示 */}
          {!loading && !resultData && (
            <>
              <Typography level='h4' mb={2}>
                Step 1: Input Sequence (FASTA format)
              </Typography>
              <FormControl sx={{ mb: 4 }}>
                <FormLabel>FASTA Sequence</FormLabel>
                <Textarea
                  minRows={6}
                  maxRows={6}
                  placeholder={`>sequence id
ATGCGT...`}
                  value={fastaInput}
                  onChange={(e) => setFastaInput(e.target.value)}
                />
              </FormControl>

              <Accordion
                expanded={expanded === 'settings'}
                onChange={(_, isExpanded) => setExpanded(isExpanded ? 'settings' : false)}>
                <AccordionSummary indicator={<ExpandMore />}>
                  <Tooltip
                    title="We recommend keeping the default settings. Adjust them only if you're familiar with the parameters."
                    variant='solid'
                    placement='top-start'>
                    <Typography level='h4'>Step 2: Settings</Typography>
                  </Tooltip>
                </AccordionSummary>
                <AccordionDetails>
                  <Box sx={{ maxHeight, overflowY: 'auto', overflowX: 'hidden' }}>
                    {Object.entries(groupedKeys).map(([group, keys]) => (
                      <Box key={group} mt={3}>
                        <Typography level='title-md' mb={1}>
                          {group}
                        </Typography>
                        <Grid container spacing={2}>
                          {keys.map((key) => (
                            <Grid xs={12} sm={6} md={4} key={key}>
                              <FormControl>
                                <Tooltip title={tooltips[key]} variant='solid' placement='top-start'>
                                  <FormLabel>{labels[key]}</FormLabel>
                                </Tooltip>
                                <Input
                                  value={params[key]}
                                  onChange={handleChange(key)}
                                  error={!validateInput(key, String(params[key]))}
                                />
                              </FormControl>
                            </Grid>
                          ))}
                        </Grid>
                      </Box>
                    ))}
                  </Box>
                </AccordionDetails>
              </Accordion>

              <Box mt={4} display='flex' justifyContent='flex-end' gap={2}>
                <Button
                  size='lg'
                  onClick={handleDesignClick}
                  variant='solid'
                  color='primary'
                  startDecorator={<DoneAllRounded />}>
                  Design
                </Button>
                <Button
                  sx={{ border: '1px solid #ced7e1' }}
                  size='lg'
                  variant='soft'
                  color='success'
                  startDecorator={<AutoAwesomeRounded />}
                  onClick={() =>
                    setFastaInput(
                      '>example1\nGTTTTTCTGACAGCTATAAGTTGTTCACAAATAGTGGACTTGGATCTATTCATAGCAGATGGAAAGAGCTTGTATGGCACAGGTGAAAGACACCCAAATTTAAAAAATTAAGGCCAAAAGGAACTGTTGCACCTCCTTCCGAGGTTTGGACCCT\n>example2\nGTTTTTCTGACAGCTATAAGTTGTTCACAAATAGTGGACTTGGA\n>example3\nGTTTTTCTGACAGCTAT'
                    )
                  }>
                  Example
                </Button>
                <Button
                  size='lg'
                  onClick={handleReset}
                  sx={{ border: '1px solid #ced7e1' }}
                  color='neutral'
                  variant='plain'
                  startDecorator={<CancelRounded />}>
                  Reset
                </Button>
              </Box>
            </>
          )}

          {/* Loading 页面 */}
          {loading && (
            <Box display='flex' justifyContent='center' alignItems='center' minHeight='40vh'>
              <Typography level='h4'>Designing... Please wait</Typography>
            </Box>
          )}

          {/* 结果显示部分 */}
          {resultData && (
            <>
              <ResultsTable data={resultData.results} />
              <Box mt={4} display='flex' justifyContent='flex-end' gap={2}>
                <Button
                  size='lg'
                  onClick={handleReset}
                  variant='solid'
                  color='primary'
                  startDecorator={<ReplayRounded />}>
                  Redesign
                </Button>

                {/* <Button
                  size='lg'
                  onClick={handleSave}
                  variant='soft'
                  color='success'
                  startDecorator={<SaveRounded />}
                  sx={{ border: '1px solid #ced7e1' }}>
                  Save
                </Button> */}
              </Box>
            </>
          )}
        </Box>

        {/* error snackbar */}
        {error && (
          <Snackbar
            open
            color='danger'
            variant='outlined'
            autoHideDuration={5000}
            onClose={() => setError(null)}
            anchorOrigin={{ vertical: 'top', horizontal: 'center' }}>
            <Box display='flex' alignItems='center' gap={1}>
              <ErrorOutlineRoundedIcon color='error' fontSize='small' />
              <strong>Error:</strong> {error}
            </Box>
          </Snackbar>
        )}
      </PanelBody>
    </>
  )
}

export default ASODesign
